/* ========================================================================
 * Network Joining Process
 * ======================================================================== */

static int zigbee_send_association_request(zigbee_light_device_t *dev,
                                            network_scan_result_t *network)
{
    if (!dev || !network) return -1;

    printf("[JOIN] Sending association request to PAN 0x%04X\n", network->pan_id);

    /* Build MAC association request frame */
    uint8_t assoc_req[32];
    uint8_t idx = 0;

    /* Frame control */
    assoc_req[idx++] = 0x23;  /* MAC command, ack request, src addr long */
    assoc_req[idx++] = 0xC8;

    /* Sequence number */
    assoc_req[idx++] = 0x01;

    /* Destination PAN ID */
    assoc_req[idx++] = (uint8_t)(network->pan_id & 0xFF);
    assoc_req[idx++] = (uint8_t)(network->pan_id >> 8);

    /* Destination address (coordinator) */
    assoc_req[idx++] = 0x00;
    assoc_req[idx++] = 0x00;

    /* Source PAN ID (broadcast during association) */
    assoc_req[idx++] = 0xFF;
    assoc_req[idx++] = 0xFE;

    /* Source IEEE address */
    uint64_t ieee = dev->descriptor.ieee_address;
    for (int i = 0; i < 8; i++) {
        assoc_req[idx++] = (uint8_t)(ieee >> (i * 8));
    }

    /* Command: Association Request */
    assoc_req[idx++] = 0x01;

    /* Capability information:
     * Bit 1: Device type (1 = FFD/Router capable)
     * Bit 2: Power source (1 = mains powered)
     * Bit 3: Rx on when idle (1 = yes, light is always on)
     * Bit 6: Security capability (1 = yes) */
    assoc_req[idx++] = 0x8E;  /* Mains powered, RxOnIdle, Security capable */

    dev->state = DEVICE_STATE_JOINING;

    return zigbee_hal_radio_transmit(assoc_req, idx);
}

static int zigbee_process_association_response(zigbee_light_device_t *dev,
                                                const uint8_t *frame,
                                                uint8_t frame_len)
{
    if (!dev || !frame || frame_len < 4) return -1;

    printf("[JOIN] Processing association response...\n");

    /* Parse short address from response (simplified) */
    uint16_t short_addr = (uint16_t)(frame[0] | (frame[1] << 8));
    uint8_t status = frame[2];

    if (status == 0x00) {
        dev->descriptor.short_address = short_addr;
        printf("[JOIN] Association successful! Short address: 0x%04X\n", short_addr);
        dev->state = DEVICE_STATE_AUTHENTICATING;
        return 0;
    } else {
        printf("[JOIN] Association failed with status: 0x%02X\n", status);
        dev->state = DEVICE_STATE_ERROR;
        return -1;
    }
}

static join_status_t zigbee_join_network(zigbee_light_device_t *dev,
                                          network_scan_result_t *network)
{
    if (!dev || !network) return JOIN_STATUS_UNKNOWN_ERROR;

    printf("\n[JOIN] ===== Starting Network Join Process =====\n");
    printf("[JOIN] Target: PAN=0x%04X, Channel=%d\n", network->pan_id, network->channel);

    /* Step 1: Initialize radio on target channel */
    if (zigbee_hal_radio_init(network->channel) != 0) {
        printf("[JOIN] ERROR: Failed to init radio\n");
        return JOIN_STATUS_UNKNOWN_ERROR;
    }

    /* Step 2: Send MAC association request */
    if (zigbee_send_association_request(dev, network) != 0) {
        printf("[JOIN] ERROR: Failed to send association request\n");
        return JOIN_STATUS_UNKNOWN_ERROR;
    }

    /* Step 3: Wait for association response (simulated) */
    printf("[JOIN] Waiting for association response...\n");
    zigbee_hal_delay_ms(500);

    /* Simulate successful association */
    uint8_t sim_response[] = {0x01, 0x00, 0x00};  /* Short addr 0x0001, success */
    if (zigbee_process_association_response(dev, sim_response, sizeof(sim_response)) != 0) {
        return JOIN_STATUS_AUTH_FAILED;
    }

    /* Step 4: Authenticate with trust center using link key */
    printf("[JOIN] Authenticating with trust center...\n");
    dev->state = DEVICE_STATE_AUTHENTICATING;

    uint8_t sim_challenge[16] = {0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08,
                                  0x09, 0x0A, 0x0B, 0x0C, 0x0D, 0x0E, 0x0F, 0x10};

    if (trust_center_authenticate(&dev->tc_config, sim_challenge, 16) != 0) {
        printf("[JOIN] ERROR: Trust center authentication failed\n");
        dev->state = DEVICE_STATE_ERROR;
        return JOIN_STATUS_AUTH_FAILED;
    }

    /* Step 5: Receive and install network key via transport key command */
    printf("[JOIN] Performing key exchange...\n");
    dev->state = DEVICE_STATE_KEY_EXCHANGE;

    uint8_t sim_transport_key[16] = {0xAA, 0xBB, 0xCC, 0xDD, 0xEE, 0xFF,
                                      0x11, 0x22, 0x33, 0x44, 0x55, 0x66,
                                      0x77, 0x88, 0x99, 0x00};

    if (trust_center_key_exchange(&dev->tc_config, &dev->network_key,
                                   sim_transport_key, 16) != 0) {
        printf("[JOIN] ERROR: Key exchange failed\n");
        dev->state = DEVICE_STATE_ERROR;
        return JOIN_STATUS_KEY_EXCHANGE_FAILED;
    }

    /* Step 6: Send device announce */
    printf("[JOIN] Sending device announce...\n");
    uint8_t dev_announce[16];
    uint8_t idx = 0;
    dev_announce[idx++] = 0x09;  /* NWK command frame */
    dev_announce[idx++] = 0x13;  /* Device announce */
    dev_announce[idx++] = (uint8_t)(dev->descriptor.short_address & 0xFF);
    dev_announce[idx++] = (uint8_t)(dev->descriptor.short_address >> 8);

    uint64_t ieee = dev->descriptor.ieee_address;
    for (int i = 0; i < 8; i++) {
        dev_announce[idx++] = (uint8_t)(ieee >> (i * 8));
    }
    dev_announce[idx++] = 0x8E;  /* Capability */

    zigbee_hal_radio_transmit(dev_announce, idx);

    /* Join successful */
    dev->state = DEVICE_STATE_NETWORK_JOINED;
    printf("[JOIN] ===== Network Join SUCCESSFUL =====\n");
    printf("[JOIN] Short Address: 0x%04X\n", dev->descriptor.short_address);
    printf("[JOIN] PAN ID: 0x%04X\n", network->pan_id);
    printf("[JOIN] Channel: %d\n", network->channel);

    return JOIN_STATUS_SUCCESS;
}

/* ========================================================================
 * Permit Join Management
 * ======================================================================== */

static int zigbee_permit_join_enable(zigbee_light_device_t *dev, uint8_t duration)
{
    if (!dev) return -1;

    if (dev->state < DEVICE_STATE_NETWORK_JOINED) {
        printf("[PERMIT] ERROR: Not joined to network, cannot enable permit join\n");
        return -1;
    }

    printf("[PERMIT] Enabling permit join for %d seconds\n",
           duration == 254 ? -1 : duration);

    /* Build Mgmt_Permit_Joining_req ZDP command */
    uint8_t permit_frame[8];
    uint8_t idx = 0;
    permit_frame[idx++] = 0x09;    /* Frame type */
    permit_frame[idx++] = 0x36;    /* ZDP Mgmt_Permit_Joining_req cluster (0x0036) */
    permit_frame[idx++] = 0x00;
    permit_frame[idx++] = duration; /* Permit join duration */
    permit_frame[idx++] = 0x01;    /* TC_Significance: TRUE */

    int ret = zigbee_hal_radio_transmit(permit_frame, idx);
    if (ret == 0) {
        dev->permit_join_active = true;
        dev->permit_join_remaining = duration;
        printf("[PERMIT] Permit join enabled successfully\n");
    }

    return ret;
}

static int zigbee_permit_join_disable(zigbee_light_device_t *dev)
{
    if (!dev) return -1;

    printf("[PERMIT] Disabling permit join\n");

    uint8_t permit_frame[8];
    uint8_t idx = 0;
    permit_frame[idx++] = 0x09;
    permit_frame[idx++] = 0x36;
    permit_frame[idx++] = 0x00;
    permit_frame[idx++] = 0x00;    /* Duration = 0 (disable) */
    permit_frame[idx++] = 0x01;

    int ret = zigbee_hal_radio_transmit(permit_frame, idx);
    if (ret == 0) {
        dev->permit_join_active = false;
        dev->permit_join_remaining = 0;
        printf("[PERMIT] Permit join disabled\n");
    }

    return ret;
}

static void zigbee_permit_join_tick(zigbee_light_device_t *dev)
{
    if (!dev || !dev->permit_join_active) return;

    if (dev->permit_join_remaining == 254) {
        /* Indefinite mode, no countdown */
        return;
    }

    if (dev->permit_join_remaining > 0) {
        dev->permit_join_remaining--;
        if (dev->permit_join_remaining == 0) {
            printf("[PERMIT] Permit join timer expired\n");
            zigbee_permit_join_disable(dev);
        }
    }
}

