static void light_init(light_state_t *light)
{
    if (!light) return;

    light->on_off = false;
    light->brightness = 254;    /* Full brightness default */
    light->color_temp = 370;    /* Warm white ~2700K */
    light->hue = 0;
    light->saturation = 0;

    printf("[LIGHT] Light state initialized (OFF, brightness=254, temp=370)\n");
}

static void light_set_on_off(light_state_t *light, bool on)
{
    if (!light) return;

    light->on_off = on;
    zigbee_hal_gpio_set_led(on);
    printf("[LIGHT] Light turned %s\n", on ? "ON" : "OFF");
}

static void light_set_brightness(light_state_t *light, uint8_t level)
{
    if (!light) return;

    light->brightness = level;
    if (level > 0 && !light->on_off) {
        light->on_off = true;
        zigbee_hal_gpio_set_led(true);
    } else if (level == 0) {
        light->on_off = false;
        zigbee_hal_gpio_set_led(false);
    }

    printf("[LIGHT] Brightness set to %d\n", level);
}

